script.text:
      &OutlineEntry;

function loadForm$&controller;$Dir(f) {
  if (f._action == 'Edit') setItem$&controller;$Disable(f, 'ma_so', true);
    else if (f._action == 'New') setItem$&controller;$Disable(f, 'ma_so', false);
  onChange$&controller;$CalculateType(f);
}
function onChange$&controller;$Item(o) {
  onChange$&controller;$CalculateType(o.parentForm, true);
}
function onChange$&controller;$CalculateType(f, force) {window.setTimeout(String.format('onFocus$&controller;$CalculateType(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$&controller;$CalculateType(id, force) {
  var f = $find(id), o = f.getItem('nguon_dl'), v = (f.getItem('kind').value == 1), u = (!v&&((o.value == 7)||(o.value == 8))), a = f._action == 'View';
  var c = (!v&&((o.value != 7)&&(o.value != 8)));
  var l = (o.value)%2 == 1;
  setItem$&controller;$AllowNulls(f, 'ds_tk', v);
  setFields$&controller;$Empty(f, 'ds_tk', v);
  setItem$&controller;$Disable(f, 'ds_tk', !v);
  setItem$&controller;$Disable(f, 'nguon_dl', v||a);
  setFocus$&controller;$Item(f, 'nguon_dl', !v&&force);
  setFocus$&controller;$Item(f, 'ds_tk', v&&force);
  setItem$&controller;$AllowNulls(f, 'ds_chi_tieu', u);
  setFields$&controller;$Empty(f, 'ds_chi_tieu', u);
  setItem$&controller;$Disable(f, 'ds_chi_tieu, thu_chi', !u);
  if (force) if (!l&&c) {f.setItemValue('thu_chi', 2);} else f.setItemValue('thu_chi', 1);
}
function setItem$&controller;$AllowNulls(f, c, v) {
  var o = f.getItem($func.trim(c));
  var grandNode = o.parentNode.parentNode;
  if (!v) {
    o.field.AllowNulls = true;
    Sys.UI.DomElement.removeCssClass(grandNode, 'Required');
  } else {
    o.field.AllowNulls = false;
    Sys.UI.DomElement.addCssClass(grandNode, 'Required');
    Sys.UI.DomElement.addCssClass(grandNode, f._id);
  }
}
function setItem$&controller;$Disable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
function setFields$&controller;$Empty(f, c, v){
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if(!v) o.value = '';
  }
}
function setFocus$&controller;$Item(f, c, v){
  if(v) f.getItem($func.trim(c)).focus();
}

      &ScriptIrregular;
